/*! block SW register during tests */
(() => {
  if (!('serviceWorker' in navigator)) return;
  const orig = navigator.serviceWorker.register.bind(navigator.serviceWorker);
  navigator.serviceWorker.register = async function() {
    console.warn('[sw-off] serviceWorker.register 차단됨(테스트용)');
    return Promise.reject(new Error('[sw-off] blocked during tests'));
  };
})();